package trackerweb

import (
	"html/template"

	"github.com/labstack/echo/v5"
)

var pages = template.Must(template.New("pages").Parse(loginTemplate + workerRegistrationTemplate + workerTemplate + workerTokenTemplate + dashboardTemplate + projectTemplate + usersTemplate + tokenTemplate + jobTemplate + errorTemplate))

func render(ctx *echo.Context, status int, name string, data any) error {
	ctx.Response().Header().Set("Content-Type", "text/html; charset=utf-8")
	ctx.Response().WriteHeader(status)
	return pages.ExecuteTemplate(ctx.Response(), name, data)
}

const loginTemplate = `{{define "login"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>SavewebHQ sign in</title><link rel="stylesheet" href="/assets/admin.css"></head><body class="login-body"><main class="login"><div class="brand">SavewebHQ</div><h1>Sign in</h1><a class="button primary" href="/auth/github/start">Continue with GitHub</a></main></body></html>{{end}}`

const workerRegistrationTemplate = `{{define "worker-registration"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Worker registration · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body class="login-body"><main class="login"><div class="brand">SavewebHQ</div><h1>Worker registration</h1><p><strong>{{.User.GitHubLogin}}</strong> · <code>{{.User.Status}}</code></p><a class="button" href="/">Return</a></main></body></html>{{end}}`

const workerTemplate = `{{define "worker"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Worker · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body><header><a class="brand" href="/worker">SavewebHQ</a><div class="account"><span>{{.User.GitHubLogin}}</span><form method="post" action="/logout"><input type="hidden" name="csrf" value="{{.CSRF}}"><button class="quiet" type="submit">Sign out</button></form></div></header><main><div class="page-title"><div><h1>Worker</h1><p><code>{{.User.ID}}</code></p></div></div><section class="table-wrap"><table><tbody><tr><th>Status</th><td>{{.User.Status}}</td></tr><tr><th>Machine token</th><td>{{if .TokenActive}}active{{else}}none{{end}}</td></tr></tbody></table></section><section class="form-band actions"><form method="post" action="/worker/token"><input type="hidden" name="csrf" value="{{.CSRF}}"><button class="primary" type="submit">{{if .TokenActive}}Rotate token{{else}}Generate token{{end}}</button></form>{{if .TokenActive}}<form method="post" action="/worker/token/revoke"><input type="hidden" name="csrf" value="{{.CSRF}}"><button class="danger" type="submit">Revoke token</button></form>{{end}}</section></main></body></html>{{end}}`

const workerTokenTemplate = `{{define "worker-token"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Machine token · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body><header><a class="brand" href="/worker">SavewebHQ</a><div class="account"><span>{{.User.GitHubLogin}}</span><form method="post" action="/logout"><input type="hidden" name="csrf" value="{{.CSRF}}"><button class="quiet" type="submit">Sign out</button></form></div></header><main><h1>Machine token</h1><section class="form-band"><label>Copy now<textarea rows="4" readonly>{{.Token}}</textarea></label></section><p><a class="button" href="/worker">Done</a></p></main></body></html>{{end}}`

const dashboardTemplate = `{{define "dashboard"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Projects · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body><header><a class="brand" href="/admin">SavewebHQ</a><div class="account"><span>{{.User.GitHubLogin}}</span><form method="post" action="/logout"><input type="hidden" name="csrf" value="{{.CSRF}}"><button class="quiet" type="submit">Sign out</button></form></div></header><main><div class="page-title"><div><h1>Projects</h1><p>{{len .Projects}} registered</p></div><a class="button" href="/admin/users">Users</a></div><section class="table-wrap"><table><thead><tr><th>Project</th><th>Status</th><th>Identity</th><th>Todo</th><th>WIP</th><th>Done</th><th>Failed</th><th>Exhausted</th></tr></thead><tbody>{{range .Projects}}<tr><td><a href="/admin/projects/{{.ID}}"><code>{{.ID}}</code></a></td><td><span class="status {{.Status}}">{{.Status}}</span></td><td><code>{{.IdentityMode}}</code></td><td>{{index .JobCounts "todo"}}</td><td>{{index .JobCounts "wip"}}</td><td>{{index .JobCounts "done"}}</td><td>{{index .JobCounts "failed"}}</td><td>{{index .JobCounts "reset_exhausted"}}</td></tr>{{else}}<tr><td colspan="8" class="empty">No projects</td></tr>{{end}}</tbody></table></section><section class="form-band"><h2>Create project</h2><form method="post" action="/admin/projects" class="inline-form"><input type="hidden" name="csrf" value="{{.CSRF}}"><label>Project ID<input name="project_id" maxlength="128" pattern="[A-Za-z0-9._:-]+" required></label><label>Status<select name="status"><option value="active">Active</option><option value="draining">Draining</option><option value="archived">Archived</option></select></label><label>Identity<select name="identity_mode"><option value="external_id">External ID</option><option value="unique_value">Unique value</option><option value="none">None</option></select></label><button class="primary" type="submit">Create project</button></form></section></main></body></html>{{end}}`

const projectTemplate = `{{define "project"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{{.Project.ID}} · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body><header><a class="brand" href="/admin">SavewebHQ</a><div class="account"><span>{{.User.GitHubLogin}}</span><form method="post" action="/logout"><input type="hidden" name="csrf" value="{{.CSRF}}"><button class="quiet" type="submit">Sign out</button></form></div></header><main><div class="breadcrumbs"><a href="/admin">Projects</a><span>/</span><code>{{.Project.ID}}</code></div><div class="page-title"><div><h1>{{.Project.ID}}</h1><p>Created {{.Project.CreatedAt}} · Updated {{.Project.UpdatedAt}} · Identity {{.Project.IdentityMode}}</p></div><form method="post" action="/admin/projects/{{.Project.ID}}/status" class="status-form"><input type="hidden" name="csrf" value="{{.CSRF}}"><select name="status"><option value="active" {{if eq .Project.Status "active"}}selected{{end}}>Active</option><option value="draining" {{if eq .Project.Status "draining"}}selected{{end}}>Draining</option><option value="archived" {{if eq .Project.Status "archived"}}selected{{end}}>Archived</option></select><button type="submit">Save status</button></form></div><section class="metrics"><div><span>Todo</span><strong>{{index .Project.JobCounts "todo"}}</strong></div><div><span>WIP</span><strong>{{index .Project.JobCounts "wip"}}</strong></div><div><span>Done</span><strong>{{index .Project.JobCounts "done"}}</strong></div><div><span>Failed</span><strong>{{index .Project.JobCounts "failed"}}</strong></div><div><span>Exhausted</span><strong>{{index .Project.JobCounts "reset_exhausted"}}</strong></div></section><section class="form-band"><h2>Jobs</h2><div class="table-wrap"><table><thead><tr><th>ID</th><th>Status</th><th>Value</th><th>External ID</th></tr></thead><tbody>{{range .Jobs}}<tr><td><a href="/admin/projects/{{$.Project.ID}}/jobs/{{.JobID}}">{{.JobID}}</a></td><td>{{.Status}}</td><td><code>{{.Value}}</code></td><td><code>{{.ID}}</code></td></tr>{{else}}<tr><td colspan="4" class="empty">No jobs</td></tr>{{end}}</tbody></table></div></section><section class="form-band"><h2>Enqueue jobs</h2><form method="post" action="/admin/projects/{{.Project.ID}}/jobs"><input type="hidden" name="csrf" value="{{.CSRF}}"><label>Job batch<textarea name="jobs_json" rows="12" spellcheck="false" required>{{.JobExample}}</textarea></label><div class="actions"><button class="primary" type="submit">Enqueue jobs</button></div></form><form method="post" enctype="multipart/form-data" action="/admin/projects/{{.Project.ID}}/source" class="source-form"><input type="hidden" name="csrf" value="{{.CSRF}}"><label>Source file<input type="file" name="source_file" accept=".zst,application/zstd" required></label><button type="submit">Import source</button></form></section><section class="form-band"><form method="post" action="/admin/projects/{{.Project.ID}}/delete"><input type="hidden" name="csrf" value="{{.CSRF}}"><button type="submit">Delete project</button></form></section></main></body></html>{{end}}`

const usersTemplate = `{{define "users"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Users · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body><header><a class="brand" href="/admin">SavewebHQ</a></header><main><div class="breadcrumbs"><a href="/admin">Projects</a><span>/</span><span>Users</span></div><div class="page-title"><div><h1>Users</h1><p>{{len .Users}} registered</p></div></div><section class="table-wrap"><table><thead><tr><th>User</th><th>Status</th><th>Roles</th><th>Token</th><th>Actions</th></tr></thead><tbody>{{range .Users}}<tr class="{{if and $.Editing (eq .ID $.EditUser.ID)}}selected-row{{end}}"><td><a class="user-link" href="/admin/users?user_id={{.ID}}#user-form"><code>{{.ID}}</code>{{if .GitHubLogin}} · {{.GitHubLogin}}{{end}}</a></td><td>{{.Status}}</td><td>{{range .Roles}}<code>{{.}}</code> {{end}}</td><td>{{if .MachineTokenActive}}active{{else}}none{{end}}</td><td><form class="inline-form" method="post" action="/admin/users/{{.ID}}/token"><input type="hidden" name="csrf" value="{{$.CSRF}}"><button type="submit">Rotate token</button></form>{{if .MachineTokenActive}}<form class="inline-form" method="post" action="/admin/users/{{.ID}}/token/revoke"><input type="hidden" name="csrf" value="{{$.CSRF}}"><button type="submit">Revoke</button></form>{{end}}<form class="inline-form" method="post" action="/admin/users/{{.ID}}/delete"><input type="hidden" name="csrf" value="{{$.CSRF}}"><button class="danger" type="submit">Delete</button></form></td></tr>{{else}}<tr><td colspan="5" class="empty">No users</td></tr>{{end}}</tbody></table></section><section class="form-band" id="user-form"><h2>{{if .Editing}}Update user{{else}}Create user{{end}}</h2><form method="post" action="/admin/users" class="inline-form"><input type="hidden" name="csrf" value="{{.CSRF}}"><label>User ID<input name="user_id" maxlength="128" pattern="[A-Za-z0-9._:-]+" value="{{if .Editing}}{{.EditUser.ID}}{{end}}" {{if .Editing}}readonly{{end}} required></label><label>Status<select name="status"><option value="active" {{if or (not .Editing) (eq .EditUser.Status "active")}}selected{{end}}>Active</option><option value="suspended" {{if and .Editing (eq .EditUser.Status "suspended")}}selected{{end}}>Suspended</option><option value="pending" {{if and .Editing (eq .EditUser.Status "pending")}}selected{{end}}>Pending</option></select></label><label><input type="checkbox" name="roles" value="worker" {{if .EditWorker}}checked{{end}}> Worker</label><label><input type="checkbox" name="roles" value="admin" {{if .EditAdmin}}checked{{end}}> Admin</label><button class="primary" type="submit">Save user</button>{{if .Editing}}<a class="button" href="/admin/users">Cancel</a>{{end}}</form></section></main></body></html>{{end}}`

const tokenTemplate = `{{define "token"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Machine token · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body><header><a class="brand" href="/admin">SavewebHQ</a></header><main><div class="breadcrumbs"><a href="/admin/users">Users</a><span>/</span><code>{{.UserID}}</code></div><h1>Machine token</h1><section class="form-band"><label>Copy now<textarea rows="4" readonly>{{.Token}}</textarea></label></section><p><a class="button" href="/admin/users">Done</a></p></main></body></html>{{end}}`

const jobTemplate = `{{define "job"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Job {{.Job.JobID}} · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body><header><a class="brand" href="/admin">SavewebHQ</a></header><main><div class="breadcrumbs"><a href="/admin">Projects</a><span>/</span><a href="/admin/projects/{{.ProjectID}}"><code>{{.ProjectID}}</code></a><span>/</span><span>Job {{.Job.JobID}}</span></div><div class="page-title"><div><h1>Job {{.Job.JobID}}</h1><p>Status {{.Job.Status}} · resets {{.Job.ResetCount}}</p></div></div><section class="table-wrap"><table><tbody><tr><th>Value</th><td><code>{{.Job.Value}}</code></td></tr><tr><th>External ID</th><td><code>{{.Job.ID}}</code></td></tr><tr><th>Type</th><td>{{.Job.Type}}</td></tr><tr><th>Via</th><td><code>{{.Job.Via}}</code></td></tr><tr><th>Worker</th><td><code>{{.Job.WorkerID}}</code></td></tr><tr><th>Lease</th><td>{{.Job.LeaseExpiresAt}}</td></tr><tr><th>Attributes</th><td><pre><code>{{.AttrsJSON}}</code></pre></td></tr><tr><th>Outcome</th><td><pre><code>{{.OutcomeJSON}}</code></pre></td></tr><tr><th>Execution error</th><td><pre><code>{{.ErrorJSON}}</code></pre></td></tr><tr><th>WARC receipts</th><td><pre><code>{{.ReceiptsJSON}}</code></pre></td></tr><tr><th>Created</th><td>{{.Job.CreatedAt}}</td></tr><tr><th>Updated</th><td>{{.Job.UpdatedAt}}</td></tr></tbody></table></section><section class="form-band actions">{{if or (eq .Job.Status "failed") (eq .Job.Status "reset_exhausted")}}<form method="post" action="/admin/projects/{{.ProjectID}}/jobs/{{.Job.JobID}}/requeue"><input type="hidden" name="csrf" value="{{.CSRF}}"><button class="primary" type="submit">Requeue</button></form>{{end}}{{if ne .Job.Status "wip"}}<form method="post" action="/admin/projects/{{.ProjectID}}/jobs/{{.Job.JobID}}/delete"><input type="hidden" name="csrf" value="{{.CSRF}}"><button type="submit">Delete job</button></form>{{end}}</section></main></body></html>{{end}}`

const errorTemplate = `{{define "error"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Request failed · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body class="login-body"><main class="login"><div class="brand">SavewebHQ</div><h1>Request failed</h1><p>{{.Message}}</p><a class="button" href="/">Return</a></main></body></html>{{end}}`

const adminCSS = `:root{color-scheme:light;--ink:#17201c;--muted:#66716b;--line:#d9dfdc;--paper:#fff;--wash:#f4f6f5;--green:#176b45;--green-dark:#0e4e31;--amber:#8a5a00;--red:#a12b2b}*{box-sizing:border-box}body{margin:0;background:var(--wash);color:var(--ink);font:14px/1.45 ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;letter-spacing:0}a{color:var(--green-dark)}header{height:58px;padding:0 max(20px,calc((100vw - 1180px)/2));display:flex;align-items:center;justify-content:space-between;background:var(--ink);color:#fff}.brand{font-size:18px;font-weight:750;color:inherit;text-decoration:none}.account{display:flex;align-items:center;gap:16px}.account form{margin:0}main{max-width:1180px;margin:0 auto;padding:32px 20px 72px}.page-title{display:flex;align-items:flex-end;justify-content:space-between;gap:24px;margin-bottom:24px}h1{font-size:28px;line-height:1.15;margin:0 0 4px}h2{font-size:18px;margin:0 0 18px}.page-title p,.login p{margin:0;color:var(--muted)}.table-wrap{overflow:auto;background:var(--paper);border:1px solid var(--line)}table{width:100%;border-collapse:collapse;white-space:nowrap}th,td{text-align:left;padding:12px 14px;border-bottom:1px solid var(--line)}th{font-size:12px;text-transform:uppercase;color:var(--muted);background:#f8f9f8}tbody tr:last-child td{border-bottom:0}.selected-row td{background:#edf5f0}.user-link{color:inherit;text-decoration:none}.user-link:hover{text-decoration:underline}code,textarea,pre{font-family:ui-monospace,SFMono-Regular,Consolas,monospace}pre{margin:0;white-space:pre-wrap}.status{font-weight:650}.status.active{color:var(--green)}.status.draining{color:var(--amber)}.status.archived{color:var(--muted)}.empty{text-align:center;color:var(--muted);padding:32px}.form-band{margin-top:32px;padding-top:28px;border-top:1px solid var(--line)}form.inline-form,.status-form{display:flex;align-items:end;gap:12px;flex-wrap:wrap}label{display:grid;gap:6px;font-weight:650}input,select,textarea,button,.button{min-height:38px;border:1px solid #aeb8b3;border-radius:5px;background:#fff;color:var(--ink);font:inherit;letter-spacing:0;padding:8px 10px}input{min-width:240px}textarea{width:100%;resize:vertical;line-height:1.5}button,.button{display:inline-flex;align-items:center;justify-content:center;font-weight:700;text-decoration:none;cursor:pointer}.primary{background:var(--green);border-color:var(--green);color:#fff}.primary:hover{background:var(--green-dark)}.danger{color:var(--red);border-color:var(--red)}.quiet{min-height:32px;padding:5px 9px;background:transparent;border-color:#59635e;color:#fff}.breadcrumbs{display:flex;gap:8px;color:var(--muted);margin-bottom:18px}.metrics{display:grid;grid-template-columns:repeat(5,minmax(110px,1fr));border:1px solid var(--line);background:var(--paper)}.metrics div{padding:16px;border-right:1px solid var(--line)}.metrics div:last-child{border-right:0}.metrics span{display:block;color:var(--muted);font-size:12px;text-transform:uppercase}.metrics strong{display:block;font-size:25px;margin-top:4px}.actions{margin-top:12px;display:flex;gap:12px;flex-wrap:wrap}.login-body{min-height:100vh;display:grid;place-items:center}.login{width:min(420px,calc(100% - 40px));padding:36px;border-top:4px solid var(--green);background:var(--paper);box-shadow:0 8px 24px rgba(23,32,28,.1)}.login h1{margin:18px 0 24px}input[type=checkbox]{min-width:auto;min-height:auto}.login .button{margin-top:22px}@media(max-width:720px){header{padding:0 16px}main{padding:24px 16px 56px}.page-title{align-items:flex-start;flex-direction:column}.metrics{grid-template-columns:repeat(2,1fr)}.metrics div{border-bottom:1px solid var(--line)}.inline-form label,.inline-form input,.inline-form select,.inline-form button{width:100%}.account span{display:none}}`
